import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';
import { useAuth } from '../../context/AuthContext';
import AnimatedNumber from '../../components/AnimatedNumber';

function DetailModal({ title, icon, onClose, children, count }) {
  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal" style={{ maxWidth: 720 }}>
        <div className="modal-header">
          <span className="modal-title">{icon} {title}</span>
          <button className="modal-close" onClick={onClose}>×</button>
        </div>
        <div style={{ maxHeight: '65vh', overflowY: 'auto' }}>
          {children}
        </div>
        <div style={{ padding:'12px 20px', borderTop:'1px solid var(--border)', fontSize:13, color:'var(--text-muted)', background:'#f8fafc' }}>
          Total: <strong>{count}</strong> record{count !== 1 ? 's' : ''}
        </div>
      </div>
    </div>
  );
}

const STATUS_BADGE = { submitted:'badge-yellow', approved:'badge-green', rejected:'badge-red' };

export default function HodDashboard() {
  const { user }  = useAuth();
  const [data,    setData]    = useState(null);
  const [loading, setLoading] = useState(true);
  const [modal,   setModal]   = useState(null);
  const [modalData, setModalData]   = useState([]);
  const [loadingModal, setLoadingModal] = useState(false);

  useEffect(() => {
    axios.get('/api/hod/stats')
      .then(res => { setData(res.data); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  const openModal = async (type, title, icon) => {
    setModal({ type, title, icon });
    setModalData([]);
    setLoadingModal(true);
    try {
      if (type === 'students') {
        const res = await axios.get('/api/hod/students');
        setModalData(res.data.students);
      } else if (type === 'faculty') {
        const res = await axios.get('/api/hod/faculty');
        setModalData(res.data.faculty);
      } else if (type === 'subjects') {
        const res = await axios.get('/api/hod/subjects');
        setModalData(res.data.subjects);
      } else if (type === 'sections') {
        const res = await axios.get('/api/hod/sections');
        setModalData(res.data.sections);
      } else if (type === 'pending') {
        const res = await axios.get('/api/hod/marks', { params: { status: 'submitted' } });
        setModalData(res.data.marks);
      } else if (type === 'approved') {
        const res = await axios.get('/api/hod/marks', { params: { status: 'approved' } });
        setModalData(res.data.marks);
      } else if (type === 'rejected') {
        const res = await axios.get('/api/hod/marks', { params: { status: 'rejected' } });
        setModalData(res.data.marks);
      } else if (type === 'locked') {
        const res = await axios.get('/api/hod/marks');
        setModalData(res.data.marks.filter(m => m.isLocked));
      }
    } catch { setModalData([]); }
    finally { setLoadingModal(false); }
  };

  if (loading) return <div className="loading-screen"><div className="spinner"></div></div>;
  if (!data)   return <div className="empty-state"><div className="empty-icon">⚠️</div><div className="empty-text">Failed to load</div></div>;

  const { stats, studentsBySem, subjectsBySem } = data;
  const semData = studentsBySem.map(s => ({ name: `Sem ${s._id}`, students: s.count }));
  const subData = subjectsBySem.map(s => ({ name: `Sem ${s._id}`, subjects: s.count }));

  const statCards = [
    { key:'students', value:stats.totalStudents,  label:'Students',          icon:'👨‍🎓', color:'blue',   title:'All Students'         },
    { key:'faculty',  value:stats.totalFaculty,   label:'Faculty Members',   icon:'👩‍🏫', color:'green',  title:'All Faculty'          },
    { key:'subjects', value:stats.totalSubjects,  label:'Subjects',          icon:'📚', color:'cyan',   title:'All Subjects'         },
    { key:'sections', value:stats.totalSections,  label:'Sections',          icon:'🏫', color:'purple', title:'All Sections'         },
    { key:'pending',  value:stats.pendingMarks,   label:'Pending Approvals', icon:'⏳', color:'yellow', title:'Pending Marks'        },
    { key:'approved', value:stats.approvedMarks,  label:'Approved Marks',    icon:'✅', color:'green',  title:'Approved Marks'       },
    { key:'rejected', value:stats.rejectedMarks,  label:'Rejected Marks',    icon:'❌', color:'red',    title:'Rejected Marks'       },
    { key:'locked',   value:stats.lockedMarks,    label:'Locked Marks',      icon:'🔒', color:'purple', title:'Locked Marks'         },
  ];

  const renderContent = () => {
    if (loadingModal) return (
      <div className="empty-state" style={{ padding:48 }}>
        <div className="spinner" style={{ margin:'0 auto' }}></div>
      </div>
    );
    if (!modalData.length) return (
      <div className="empty-state">
        <div className="empty-icon">📭</div>
        <div className="empty-text">No records found</div>
      </div>
    );

    if (modal.type === 'students') return (
      <table>
        <thead><tr><th>#</th><th>Name</th><th>Roll No</th><th>Semester</th><th>Section</th></tr></thead>
        <tbody>
          {modalData.map((s,i) => (
            <tr key={s._id}>
              <td>{i+1}</td>
              <td className="fw-600">{s.name}</td>
              <td style={{ fontFamily:'monospace',fontSize:12 }}>{s.rollNumber}</td>
              <td><span className="badge badge-blue">Sem {s.semester}</span></td>
              <td>{s.section || '—'}</td>
            </tr>
          ))}
        </tbody>
      </table>
    );

    if (modal.type === 'faculty') return (
      <table>
        <thead><tr><th>#</th><th>Name</th><th>Roll No</th><th>Department</th></tr></thead>
        <tbody>
          {modalData.map((f,i) => (
            <tr key={f._id}>
              <td>{i+1}</td>
              <td className="fw-600">{f.name}</td>
              <td style={{ fontFamily:'monospace',fontSize:12 }}>{f.rollNumber}</td>
              <td>{f.department?.name || '—'}</td>
            </tr>
          ))}
        </tbody>
      </table>
    );

    if (modal.type === 'subjects') return (
      <table>
        <thead><tr><th>#</th><th>Subject Name</th><th>Code</th><th>Semester</th><th>Credits</th><th>Max Marks</th></tr></thead>
        <tbody>
          {modalData.map((s,i) => (
            <tr key={s._id}>
              <td>{i+1}</td>
              <td className="fw-600">{s.name}</td>
              <td><span className="badge badge-purple">{s.code}</span></td>
              <td>Sem {s.semester}</td>
              <td>{s.credits}</td>
              <td>{s.maxMidMarks}</td>
            </tr>
          ))}
        </tbody>
      </table>
    );

    if (modal.type === 'sections') return (
      <table>
        <thead><tr><th>#</th><th>Section</th><th>Semester</th><th>Department</th><th>Status</th></tr></thead>
        <tbody>
          {modalData.map((s,i) => (
            <tr key={s._id}>
              <td>{i+1}</td>
              <td><span className="badge badge-blue" style={{ fontSize:14, padding:'4px 14px' }}>Section {s.name}</span></td>
              <td>Semester {s.semester}</td>
              <td>{s.department?.name || '—'}</td>
              <td><span className={`badge ${s.isActive?'badge-green':'badge-red'}`}>{s.isActive?'Active':'Inactive'}</span></td>
            </tr>
          ))}
        </tbody>
      </table>
    );

    // marks types: pending, approved, rejected, locked
    return (
      <table>
        <thead>
          <tr><th>#</th><th>Student</th><th>Roll No</th><th>Sem</th><th>Subject</th><th>Exam</th><th>Marks</th><th>Faculty</th><th>Status</th></tr>
        </thead>
        <tbody>
          {modalData.map((m,i) => (
            <tr key={m._id}>
              <td>{i+1}</td>
              <td className="fw-600">{m.student?.name}</td>
              <td style={{ fontFamily:'monospace',fontSize:12 }}>{m.student?.rollNumber}</td>
              <td>{m.semester}</td>
              <td>{m.subject?.name} <span style={{ fontSize:11,color:'var(--text-muted)' }}>({m.subject?.code})</span></td>
              <td><span className="badge badge-blue">{m.midExam}</span></td>
              <td className="fw-600">{m.totalMarks}/30</td>
              <td className="text-muted">{m.faculty?.name}</td>
              <td>
                <span className={`badge ${STATUS_BADGE[m.status]||'badge-gray'}`}>{m.status}</span>
                {m.isLocked && <span className="badge badge-red" style={{ marginLeft:4 }}>🔒</span>}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    );
  };

  return (
    <div>
      <div className="info-box" style={{ marginBottom:20 }}>
        🏢 Department: <strong>{user?.department?.name}</strong> ({user?.department?.code}) —
        <span style={{ color:'var(--text-muted)', fontSize:12, marginLeft:6 }}>Click any card to view details</span>
      </div>

      <div className="stats-grid">
        {statCards.map(card => (
          <div key={card.key}
            className={`stat-card ${card.color}`}
            onClick={() => openModal(card.key, card.title, card.icon)}
            style={{ cursor:'pointer', userSelect:'none' }}
            title={`Click to view ${card.title}`}
          >
            <div className="stat-icon">{card.icon}</div>
            <div>
              <div className="stat-value"><AnimatedNumber value={card.value || 0} /></div>
              <div className="stat-label">{card.label}</div>
              <div style={{ fontSize:10, color:'var(--primary)', marginTop:2, fontWeight:600 }}>Click to view →</div>
            </div>
          </div>
        ))}
      </div>

      {/* Charts */}
      <div className="charts-grid">
        <div className="card">
          <div className="card-header"><span className="card-title">👨‍🎓 Students per Semester</span></div>
          <div className="card-body">
            {semData.length ? (
              <div className="chart-container">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={semData} margin={{ top:5,right:10,left:-10,bottom:5 }}>
                    <XAxis dataKey="name" tick={{ fontSize:11 }} />
                    <YAxis allowDecimals={false} tick={{ fontSize:11 }} />
                    <Tooltip />
                    <Bar dataKey="students" fill="#1a56db" radius={[4,4,0,0]} />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            ) : <div className="empty-state"><div className="empty-text">No student data</div></div>}
          </div>
        </div>

        <div className="card">
          <div className="card-header"><span className="card-title">📚 Subjects per Semester</span></div>
          <div className="card-body">
            {subData.length ? (
              <div className="chart-container">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={subData} margin={{ top:5,right:10,left:-10,bottom:5 }}>
                    <XAxis dataKey="name" tick={{ fontSize:11 }} />
                    <YAxis allowDecimals={false} tick={{ fontSize:11 }} />
                    <Tooltip />
                    <Bar dataKey="subjects" fill="#10b981" radius={[4,4,0,0]} />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            ) : <div className="empty-state"><div className="empty-text">No subject data</div></div>}
          </div>
        </div>
      </div>

      {/* Detail Modal */}
      {modal && (
        <DetailModal
          title={modal.title}
          icon={modal.icon}
          onClose={() => { setModal(null); setModalData([]); }}
          count={modalData.length}
        >
          {renderContent()}
        </DetailModal>
      )}
    </div>
  );
}
